import torch
from transformers import RagTokenizer, RagRetriever, RagTokenForGeneration

# Load company documents into a vector database
retriever = RagRetriever.from_pretrained("facebook/rag-token-base", index_name="custom_index_name", 
                                        use_dummy_dataset=True)

tokenizer = RagTokenizer.from_pretrained("facebook/rag-token-base")
generator = RagTokenForGeneration.from_pretrained("facebook/rag-token-base", retriever=retriever)

# Accept user query
user_query = "User's query here"

# Retrieve relevant context
prepared_input = retriever.prepare_query(user_query)
retrieved_docs = retriever.retrieve(prepared_input)

# Include all retrieved documents in LLM prompt
input_dict = tokenizer(user_query, retrieved_docs, return_tensors="pt")
output = generator.generate(**input_dict)

print(tokenizer.decode(output[0], skip_special_tokens=True))